sys_script.script:
/**
 * After Insert: Creates a Complaint History record when a Consumer Case is created.
 * Globals: current, previous, gs
 */
(function executeRule(current, previous) {

    var history = new GlideRecord('x_2091449_manage_0_complaint_history');
    history.initialize();

    var caseNumber = current.getValue('number');
    var shortDescription = current.getValue('short_description');

    if (!shortDescription) {
        shortDescription = 'No description provided';
    }

    history.setValue('consumer_case', current.getUniqueValue());
    history.setValue('action_type', 'created');
    history.setValue(
        'action_details',
        'Case ' + caseNumber + ' created - ' + shortDescription
    );
    history.setValue('new_state', current.state.getDisplayValue());
    history.setValue('performed_by', gs.getUserDisplayName());
    history.setValue('action_date', new GlideDateTime().getDisplayValue());

    history.insert();

})(current, previous);
